VALUES
  ('judicial-57f41407-moex-00463', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '債權人甲主張債務人乙已無力清償本票票款，未經提示本票，逕聲請法院對乙核發支付命令，該法院 應如何處理？', '["以甲無追索權為由裁定駁回其聲請", "依甲之聲請核發支付命令", "視甲有否提出本票原本再為准駁", "應訊問乙之意見後再為准駁"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00464', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於定暫時狀態之處分，下列敘述何者正確？', '["於財產權之法律關係聲請定暫時狀態之處分，以金錢請求以外之請求為限", "法院為定暫時狀態之裁定前，於認必要時，得依職權以裁定先為一定之緊急處置", "法院裁定許為定暫時狀態，而其內容與裁定前所為之緊急處置相異時，於定暫時狀態之裁定確定前， 相異之緊急處置並不失其效力", "定暫時狀態之裁定因自始不當被撤銷，而應負損害賠償責任者，如聲請人證明其無過失時，法院得 視情形減輕或免除其賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00465', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲列乙為被告向法院提起家事訴訟時，下列何者非專屬管轄？', '["離婚之訴", "確認遺囑真偽之訴", "撤銷婚姻之訴", "認領子女之訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00466', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲以乙詐欺結婚為由，列乙為被告，提起撤銷婚姻訴訟。法院以超過法定起訴期間為由，判決甲敗訴 確定（下稱前訴訟）。依甲、乙於前訴訟言詞辯論終結前之陳述可知，雙方均有難以維持婚姻之重大 事由，法院曾向甲、乙闡明是否追加離婚訴訟或提起反訴，惟甲、乙均未為之，且無不可歸責於甲、 乙之事由。下列敘述何者正確？', '["前訴訟之法院無向甲闡明「是否為離婚訴訟之變更或追加」之義務", "甲不得再以前訴訟經法官闡明而得主張之離婚事由，另行提起離婚之後訴訟", "前訴訟之法院無向乙闡明「是否提起離婚反訴」之義務", "乙於前訴訟無提起反訴之義務，得以前訴訟經法官闡明而得主張之離婚事由，另行提起離婚之後訴訟 乙、刑事訴訟法部分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00467', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '刑事訴訟法關於公務員制作之文書，下列敘述何者正確？', '["可以視情況隨時竄改或挖補", "應記載制作之年、月、日及其所屬機關，由制作人簽名", "如有增加字數，於文書上記明字數即可，無庸蓋章", "如有刪除，得使用立可白塗掉原文字，無庸蓋章"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
