  ('judicial-57f41407-moex-00471', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '刑事程序於送達在監獄或看守所之人，應如何為之？', '["送達給家屬", "應囑託監所長官送達之", "送達給辯護人", "送達給指定的好友"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
